  ('marcos', 1, 'Marcos apresenta Jesus em ritmo acelerado: anuncio de Joao Batista, batismo, tentacao, inicio do ministerio e os primeiros sinais de autoridade.', 'Marcos, associado ao circulo apostolico de Pedro.', 'Igreja primitiva sob forte expansao missionaria.', 'Cristaos, provavelmente incluindo muitos gentios, que precisavam de um retrato objetivo de Jesus.', 'Apresentar rapidamente quem Jesus e e como sua autoridade se manifesta em palavra e acao.', 'O evangelho de Marcos usa com frequencia a ideia de imediatismo, o que da senso de movimento ao relato.', 'Base editorial automatica do BibleApp'),
  ('marcos', 2, 'No inicio de Marcos, o capitulo destaca a apresentacao veloz do inicio do ministerio e da autoridade de Jesus, preparando o leitor para perceber como seguir Jesus envolve enxergar sua autoridade e caminhar com ele ate a cruz.', 'Marcos, associado ao circulo apostolico de Pedro.', 'Primeiro seculo, no contexto do ministerio de Jesus e da igreja primitiva.', 'Cristaos que precisavam de um retrato direto e dinamico de Jesus.', 'Retratar Jesus em acao, com autoridade e chamado ao discipulado.', 'Marcos usa ritmo acelerado e muita movimentacao de cenas.', 'Base editorial automatica do BibleApp'),
  ('marcos', 3, 'No inicio de Marcos, o capitulo introduz a apresentacao veloz do inicio do ministerio e da autoridade de Jesus, preparando o leitor para perceber como seguir Jesus envolve enxergar sua autoridade e caminhar com ele ate a cruz.', 'Marcos, associado ao circulo apostolico de Pedro.', 'Primeiro seculo, no contexto do ministerio de Jesus e da igreja primitiva.', 'Cristaos que precisavam de um retrato direto e dinamico de Jesus.', 'Retratar Jesus em acao, com autoridade e chamado ao discipulado.', 'Marcos usa ritmo acelerado e muita movimentacao de cenas.', 'Base editorial automatica do BibleApp')
) AS src(book_slug, chapter_number, summary, author, historical_period, audience, purpose, curiosities, source_label)
JOIN books b ON b.slug = src.book_slug
JOIN chapters c ON c.book_id = b.id AND c.chapter_number = src.chapter_number
ON CONFLICT (chapter_id) DO UPDATE SET
  summary = EXCLUDED.summary,
  author = EXCLUDED.author,
  historical_period = EXCLUDED.historical_period,
  audience = EXCLUDED.audience,
  purpose = EXCLUDED.purpose,
  curiosities = EXCLUDED.curiosities,
  source_label = EXCLUDED.source_label,
